import { IMessageComposer } from '@nitrots/nitro-renderer';

export class BlackjackInsuranceComposer implements IMessageComposer<any[]> {
    private _take: boolean;

    constructor(takeInsurance: boolean) {
        this._take = !!takeInsurance;
    }

    getMessageArray(): any[] {
        return [this._take ? 1 : 0];
    }
    dispose(): void {
        /* no-op */
    }
}
